import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';

// Small Components (Yalach Home ani Login mhanu sadhyasathi)
const Home = () => (
  <div className="container text-center py-5">
    <h1 className="fw-bold">Welcome to Apni Manzil</h1>
    <p>Tumcha Logistics Dashboard Lavkarach Tithe Disel!</p>
  </div>
);

const Login = () => (
  <div className="container text-center py-5">
    <h1 className="fw-bold">Login Page</h1>
    <p>MSME, Partner ani User Login sathi jag.</p>
  </div>
);

function App() {
  return (
    <Router>
      <div>
        {/* Simple Navbar */}
        <nav className="navbar navbar-dark bg-primary px-4 shadow-sm">
          <Link className="navbar-brand fw-bold" to="/">APNI MANZIL</Link>
          <Link to="/login" className="btn btn-light rounded-pill px-4">Login</Link>
        </nav>

        {/* Navigation Routes */}
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
